const text = $input.first().json.message.text || '';
const parts = text.trim().split(/\s+/);
const chatId = String($input.first().json.message.chat.id || '');
const userName = $input.first().json.message.from.first_name || 'Usuario';

// Comando /start
if (parts[0] === '/start') {
  return [{
    json: {
      tipo: 'start',
      chatId,
      userName,
      mensaje: 'Hola ' + userName + '! Soy tu asistente de Web Scraping.\n\nComandos disponibles:\n\n/buscar estatico [URL] - Auditoria SEO\n/buscar estatico [URL] guardar - Auditoria SEO + guardar\n/buscar dinamico [URL] [producto] - Buscar productos\n/buscar dinamico [URL] [producto] guardar - Buscar + guardar\n/reporte - Ver resumen de datos guardados\n/ayuda - Ver esta ayuda\n\nEjemplos:\n/buscar estatico https://es.wikipedia.org\n/buscar dinamico https://mercadolibre.com.co ram\n/buscar dinamico https://mercadolibre.com.co iphone-15 guardar'
    }
  }];
}

// Comando /ayuda
if (parts[0] === '/ayuda' || parts[0] === '/help') {
  return [{
    json: {
      tipo: 'ayuda',
      chatId,
      mensaje: 'COMANDOS DISPONIBLES\n====================\n\n/buscar estatico [URL]\n  Analiza estructura HTML/SEO de una web\n\n/buscar estatico [URL] guardar\n  Analiza y guarda en historico\n\n/buscar dinamico [URL] [producto]\n  Busca productos en e-commerce con IA\n\n/buscar dinamico [URL] [producto] guardar\n  Busca productos y guarda en historico\n\n/reporte\n  Muestra resumen de todos los datos guardados\n\nNOTA: Si el producto tiene mas de una palabra, usa guiones: memoria-ram'
    }
  }];
}

// Comando /reporte
if (parts[0] === '/reporte') {
  return [{
    json: { tipo: 'reporte', chatId, userName }
  }];
}

// Comando /buscar
if (parts.length < 3 || parts[0] !== '/buscar') {
  return [{
    json: {
      tipo: 'error',
      chatId,
      mensaje: 'Formato invalido. Usa /ayuda para ver los comandos disponibles.'
    }
  }];
}

const tipo = parts[1].toLowerCase();
const url = parts[2];
let buscar = '';
let guardar = false;

if (tipo === 'dinamico') {
  buscar = parts[3] || '';
  guardar = (parts[4] || '').toLowerCase() === 'guardar';
  buscar = buscar.replace(/-/g, ' ');
  if (!buscar) {
    return [{
      json: {
        tipo: 'error',
        chatId,
        mensaje: 'Para scraping dinamico necesitas indicar el producto.\nEjemplo: /buscar dinamico https://mercadolibre.com.co ram'
      }
    }];
  }
} else if (tipo === 'estatico') {
  guardar = (parts[3] || '').toLowerCase() === 'guardar';
} else {
  return [{
    json: {
      tipo: 'error',
      chatId,
      mensaje: 'Tipo no reconocido. Usa "estatico" o "dinamico".\nEjemplo: /buscar estatico https://wikipedia.org'
    }
  }];
}

return [{
  json: { tipo, url, buscar, guardar, chatId, userName, error: false }
}];

const html = $input.first().json.data || $input.first().json.body || '';
const url = $('Parser de Comando').item.json.url;
const userName = $('Parser de Comando').item.json.userName;

const titleMatch = html.match(/<title[^>]*>(.*?)<\/title>/is);
const titulo = titleMatch ? titleMatch[1].trim() : 'Sin titulo';

const descMatch = html.match(/<meta\s+name=["']description["']\s+content=["'](.*?)["']/is);
const descripcion = descMatch ? descMatch[1].trim() : 'Sin descripcion';

const countTag = (tag) => (html.match(new RegExp('<' + tag + '[\\s>]', 'gi')) || []).length;
const h1 = countTag('h1');
const h2 = countTag('h2');
const h3 = countTag('h3');
const enlaces = (html.match(/<a\s/gi) || []).length;

const textOnly = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .toLowerCase();

const stopWords = new Set(['de','la','el','en','y','a','los','del','las','un','por','con','no','una','su','para','es','al','que','se','lo','como','mas','o','pero','sus','le','ya','the','and','of','to','in','is','it','for','on','with','as','at','this','be','are','an','was','or','not','has','had','from','but']);

const wordFreq = {};
textOnly.split(/\s+/).forEach(word => {
  const clean = word.replace(/[^a-z\u00e1\u00e9\u00ed\u00f3\u00fa\u00f1\u00fc]/g, '');
  if (clean.length > 3 && !stopWords.has(clean)) {
    wordFreq[clean] = (wordFreq[clean] || 0) + 1;
  }
});

const topKeywords = Object.entries(wordFreq)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([word, count]) => word + ' (' + count + ')');

const guardar = $('Parser de Comando').item.json.guardar;
const chatId = $('Parser de Comando').item.json.chatId;
const fecha = new Date().toISOString().split('T')[0];

const saveLabel = guardar ? '\nGuardado en historico' : '\nDatos NO guardados (agrega "guardar" al comando)';

const reporte = 'AUDITORIA WEB\n' + '='.repeat(30) + '\n\nURL: ' + url + '\nTitulo: ' + titulo + '\n\nEstructura de Encabezados:\n  H1: ' + h1 + '\n  H2: ' + h2 + '\n  H3: ' + h3 + '\n\nTotal de Enlaces: ' + enlaces + '\n\nTop 10 Palabras Clave:\n  ' + topKeywords.join('\n  ') + '\n\nFecha: ' + fecha + saveLabel;

return [{
  json: {
    tipo: 'estatico', url, titulo, descripcion,
    h1, h2, h3, enlaces,
    palabras_clave: topKeywords.map(k => k.split(' (')[0]).join(', '),
    reporte, guardar, chatId, fecha, userName
  }
}];

const data = $input.first().json;
const base = data.url;
const query = data.buscar.replace(/\s+/g, '-');

let searchUrl;
if (base.includes('mercadolibre')) {
  const domainMatch = base.match(/https?:\/\/[^/]+/);
  const domain = domainMatch ? domainMatch[0] : base;
  searchUrl = 'https://listado.' + domain.replace('https://www.', '').replace('https://', '') + '/' + query;
} else if (base.includes('amazon')) {
  searchUrl = base + '/s?k=' + encodeURIComponent(data.buscar);
} else {
  searchUrl = base + '/search?q=' + encodeURIComponent(data.buscar);
}

return [{ json: { ...data, searchUrl } }];

const html = $input.first().json.data || $input.first().json.body || '';
const truncated = html.substring(0, 30000);
const query = $('Parser de Comando').item.json.buscar;

const prompt = 'Extrae TODOS los productos visibles del siguiente HTML de una busqueda de "' + query + '". Devuelve UNICAMENTE un array JSON valido. Cada objeto debe tener exactamente estos campos:
- titulo: nombre del producto
- precio: valor numerico (sin simbolos ni puntos de miles)
- moneda: codigo de moneda (COP, MXN, USD, etc)
- enlace: URL completa del producto
- vendedor: nombre del vendedor o "N/A"

HTML:
' + truncated;

return [{ json: { ...($('Parser de Comando').item.json), prompt, htmlLength: html.length } }];

