// Obtener respuesta del LLM (compatible con HTTP Request a Groq y con Cadena LLM nativa)
let llmResponse = '';
const input = $input.first().json;

// HTTP Request a Groq API
if (input.choices && input.choices[0] && input.choices[0].message) {
  llmResponse = input.choices[0].message.content || '';
}
// Cadena LLM basica de n8n
else if (input.response) {
  llmResponse = input.response;
}
else if (input.text) {
  llmResponse = input.text;
}
else if (input.output) {
  llmResponse = input.output;
}

let productos = [];
try {
  const cleaned = llmResponse
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();
  const match = cleaned.match(/\[([\s\S]*?)\]/);
  if (match) {
    productos = JSON.parse('[' + match[1] + ']');
  } else {
    productos = JSON.parse(cleaned);
  }
} catch (e) {
  return [{
    json: {
      error: true,
      reporte: 'La IA no pudo extraer productos de esta pagina. Posibles causas:\n- La pagina bloquea el scraping\n- No se encontraron productos para esa busqueda\n- El HTML es demasiado grande\n\nIntenta con otro producto o URL.',
      chatId: $('Parser de Comando').item.json.chatId,
      guardar: false,
      fecha: new Date().toISOString().split('T')[0]
    }
  }];
}

if (!Array.isArray(productos) || productos.length === 0) {
  return [{
    json: {
      error: true,
      reporte: 'No se encontraron productos para esta busqueda.',
      chatId: $('Parser de Comando').item.json.chatId,
      guardar: false,
      fecha: new Date().toISOString().split('T')[0]
    }
  }];
}

const precios = productos
  .map(p => parseFloat(String(p.precio).replace(/[^\d.]/g, '')))
  .filter(p => !isNaN(p) && p > 0);

const precioPromedio = precios.length
  ? Math.round(precios.reduce((a, b) => a + b, 0) / precios.length)
  : 0;
const masBarato = precios.length ? Math.min(...precios) : 0;
const masCaro = precios.length ? Math.max(...precios) : 0;

const query = $('Parser de Comando').item.json.buscar;
const url = $('Parser de Comando').item.json.url;
const guardar = $('Parser de Comando').item.json.guardar;
const chatId = $('Parser de Comando').item.json.chatId;
const fecha = new Date().toISOString().split('T')[0];

const moneda = productos[0].moneda || 'COP';
const saveLabel = guardar ? '\nGuardado en historico' : '\nDatos NO guardados (agrega "guardar" al comando)';

const productoBarato = productos.find(p => parseFloat(String(p.precio).replace(/[^\d.]/g, '')) === masBarato);
const productoCaro = productos.find(p => parseFloat(String(p.precio).replace(/[^\d.]/g, '')) === masCaro);

const reporte = 'REPORTE DE PRODUCTOS\n' + '='.repeat(30) + '\n\nBusqueda: ' + query + '\nFuente: ' + url + '\n\nTotal productos encontrados: ' + productos.length + '\n\nPrecio Promedio: $' + precioPromedio.toLocaleString() + ' ' + moneda + '\n\nMas Barato: $' + masBarato.toLocaleString() + ' ' + moneda + '\n  ' + (productoBarato ? productoBarato.titulo : '').substring(0, 60) + '\n\nMas Caro: $' + masCaro.toLocaleString() + ' ' + moneda + '\n  ' + (productoCaro ? productoCaro.titulo : '').substring(0, 60) + '\n\nFecha: ' + fecha + saveLabel;

return [{
  json: {
    tipo: 'dinamico', url, query, productos,
    datosJson: JSON.stringify(productos),
    precioPromedio, masBarato, masCaro,
    totalItems: productos.length,
    reporte, guardar, chatId, fecha, error: false
  }
}];

const chatId = $('Parser de Comando').item.json.chatId;
const userName = $('Parser de Comando').item.json.userName;

// Contar registros de ambas hojas
let totalEstaticos = 0;
let totalDinamicos = 0;
let ultimosEstaticos = [];
let ultimosDinamicos = [];

try {
  const estaticos = $('Leer Estaticos').all();
  totalEstaticos = estaticos.length;
  ultimosEstaticos = estaticos.slice(-3).map(item => {
    const j = item.json;
    return (j.Fecha || 'N/A') + ' | ' + (j.URL || 'N/A').substring(0, 40) + ' | ' + (j.Titulo || 'N/A').substring(0, 30);
  });
} catch(e) {}

try {
  const dinamicos = $('Leer Dinamicos').all();
  totalDinamicos = dinamicos.length;
  ultimosDinamicos = dinamicos.slice(-3).map(item => {
    const j = item.json;
    return (j.Fecha || j['Fecha '] || 'N/A') + ' | ' + (j.Query_buscado || j.Query_Buscado || 'N/A') + ' en ' + (j.URL_Origen || 'N/A').substring(0, 30);
  });
} catch(e) {}

const total = totalEstaticos + totalDinamicos;
const fecha = new Date().toISOString().split('T')[0];

let reporte = 'REPORTE DE HISTORICO\n' + '='.repeat(30) + '\n\nHola ' + userName + '!\n\nTotal registros guardados: ' + total + '\n  Auditorias Web (Estatico): ' + totalEstaticos + '\n  Busquedas E-commerce (Dinamico): ' + totalDinamicos + '\n';

if (ultimosEstaticos.length > 0) {
  reporte += '\nUltimas auditorias:\n  ' + ultimosEstaticos.join('\n  ') + '\n';
}

if (ultimosDinamicos.length > 0) {
  reporte += '\nUltimas busquedas:\n  ' + ultimosDinamicos.join('\n  ') + '\n';
}

reporte += '\nFecha del reporte: ' + fecha;
reporte += '\n\nVer graficos completos en:\nhttp://localhost:8501';

return [{ json: { reporte, chatId } }];
